1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_DISCOUNT = 15;
3	const BLOCK_SIZE = 3;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_YEARS_THRESHOLD = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const CURSED_RATE = 0.5;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	const CLAIM_DEDUCTIBLE = 100;
12	const HALF_PAYMENT_ENCHANTMENT_THRESHOLD = 8;
13	const HALF_PAYMENT_RATE = 0.5;
14	
15	const ITEM_BASE_PRICES: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	
26	type Item = { type: string; enchantment?: number; cursed?: boolean; material?: string };
27	type Customer = { yearsWithMHPCO?: number };
28	type QuoteStep = { op: "quote"; items: Item[] };
29	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: { itemType: string; amount: number }[] } };
30	type Step = QuoteStep | ClaimStep;
31	type Scenario = {
32	  customer?: Customer;
33	  steps: Step[];
34	};
35	
36	function countItemsByType(items: Item[]): Map<string, number> {
37	  const counts = new Map<string, number>();
38	  for (const item of items) {
39	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
40	  }
41	  return counts;
42	}
43	
44	function blockDiscountFor(type: string, count: number): number {
45	  const isComponent = COMPONENT_TYPES.has(type);
46	  const formsBlock = count === BLOCK_SIZE;
47	  return isComponent && formsBlock ? BLOCK_OF_THREE_DISCOUNT : 0;
48	}
49	
50	function basePremiumForGroup(type: string, count: number): number {
51	  return count * ITEM_BASE_PRICES[type] - blockDiscountFor(type, count);
52	}
53	
54	function computePolicyBase(items: Item[]): number {
55	  const itemCountsByType = countItemsByType(items);
56	  let basePremium = 0;
57	  for (const [type, count] of itemCountsByType.entries()) {
58	    basePremium += basePremiumForGroup(type, count);
59	  }
60	  return basePremium;
61	}
62	
63	function sumItemSurcharge(
64	  items: Item[],
65	  rate: number,
66	  applies: (item: Item) => boolean,
67	): number {
68	  return items
69	    .filter(applies)
70	    .reduce((sum, item) => sum + ITEM_BASE_PRICES[item.type] * rate, 0);
71	}
72	
73	function computeFirstInsuranceSurcharge(policyBase: number): number {
74	  return policyBase * FIRST_INSURANCE_RATE;
75	}
76	
77	function computeHighEnchantmentSurcharge(items: Item[]): number {
78	  return sumItemSurcharge(
79	    items,
80	    HIGH_ENCHANTMENT_RATE,
81	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
82	  );
83	}
84	
85	function computeCursedSurcharge(items: Item[]): number {
86	  return sumItemSurcharge(items, CURSED_RATE, (item) => item.cursed === true);
87	}
88	
89	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
90	  const years = customer.yearsWithMHPCO ?? 0;
91	  if (years >= LOYALTY_YEARS_THRESHOLD) {
92	    return policyBase * LOYALTY_DISCOUNT_RATE;
93	  }
94	  return 0;
95	}
96	
97	function computeFollowUpDiscount(policyBase: number, isFollowUpQuote: boolean): number {
98	  return isFollowUpQuote ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
99	}
100	
101	function computeQuotePremium(
102	  items: Item[],
103	  customer: Customer,
104	  isFollowUpQuote: boolean,
105	): number {
106	  const policyBase = computePolicyBase(items);
107	  const premium =
108	    policyBase +
109	    computeHighEnchantmentSurcharge(items) +
110	    computeCursedSurcharge(items) +
111	    computeFirstInsuranceSurcharge(policyBase) -
112	    computeLoyaltyDiscount(policyBase, customer) -
113	    computeFollowUpDiscount(policyBase, isFollowUpQuote) +
114	    PROCESSING_FEE;
115	  return Math.ceil(premium);
116	}
117	
118	function reimbursementFor(item: Item, damageAmount: number): number {
119	  const qualifiesForHalfPayment =
120	    (item.enchantment ?? 0) >= HALF_PAYMENT_ENCHANTMENT_THRESHOLD;
121	  const grossReimbursement = qualifiesForHalfPayment
122	    ? damageAmount * HALF_PAYMENT_RATE
123	    : damageAmount;
124	  return grossReimbursement - CLAIM_DEDUCTIBLE;
125	}
126	
127	function computeClaimPayout(claim: ClaimStep, quote: QuoteStep): number {
128	  const total = claim.incident.damages.reduce((sum, damage) => {
129	    const item = quote.items.find((i) => i.type === damage.itemType)!;
130	    return sum + reimbursementFor(item, damage.amount);
131	  }, 0);
132	  return Math.floor(total);
133	}
134	
135	export function runScenario(scenario: unknown): unknown {
136	  const s = scenario as Scenario;
137	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
138	
139	  const results = s.steps.map((step, index) => {
140	    if (step.op === "quote") {
141	      return { premium: computeQuotePremium(step.items, customer, index > 0) };
142	    }
143	    const quote = s.steps[step.policy] as QuoteStep;
144	    return { payout: computeClaimPayout(step, quote) };
145	  });
146	  return { results };
147	}
